import os
import shlex
import tempfile
import subprocess
from urllib.parse import unquote

from google.cloud import storage


def process_image(event, context):
    bucket_name = event.get("bucket")
    object_name = event.get("name")

    if not bucket_name or not object_name:
        return

    client = storage.Client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(object_name)

    blob.reload()
    metadata = blob.metadata or {}

    source_name = metadata.get("filename", object_name)
    options = metadata.get("options", "")

    local_input = os.path.join(tempfile.gettempdir(), os.path.basename(unquote(source_name)))
    root, ext = os.path.splitext(local_input)
    output_ext = metadata.get("output_ext", ext or ".png")
    local_output = f"{root}_converted{output_ext}"

    blob.download_to_filename(local_input)

    command = f"convert {options} {local_input} {local_output}"
    subprocess.call(command, shell=True)

    output_name = metadata.get("output_name", os.path.basename(local_output))
    bucket.blob(output_name).upload_from_filename(local_output)